"""Utility to write a clean Colab demo notebook for the chatbot.

This script is used by the assistant to reliably overwrite the demo notebook
without relying on editor tools that may append to the file.
"""

from __future__ import annotations

import os
from pathlib import Path

NOTEBOOK_CONTENT = r"""<VSCode.Cell language=\"markdown\">\n# Colab Demo: Supply Chain Chatbot + Gemini Explanations\n\nThis notebook demonstrates how to run the **supply chain optimization chatbot** from this repository in Google Colab, including:\n\n- ✅ Using **Gemini** for natural language explanations\n- ✅ Falling back to the rule-based explanation generator when the API key is missing\n\n> Note: This demo is intentionally lightweight and does not modify any core project modules.\n</VSCode.Cell>\n\n<VSCode.Cell language=\"python\">\n# 1) Install the Gemini client library (Colab-friendly)\n!pip install -q google-generativeai\n</VSCode.Cell>\n\n<VSCode.Cell language=\"python\">\n# 2) Securely set GEMINI_API_KEY in Colab\n#    (The value will not be printed.)\nimport os\nfrom getpass import getpass\n\nif \"GEMINI_API_KEY\" not in os.environ:\n    os.environ[\"GEMINI_API_KEY\"] = getpass(\"Enter your GEMINI_API_KEY (input hidden): \" )\n\nprint(\"GEMINI_API_KEY set?\", \"GEMINI_API_KEY\" in os.environ)\n</VSCode.Cell>\n\n<VSCode.Cell language=\"python\">\n# 3) Clone the repository (if needed) and install requirements\nimport os\n\nrepo_dir = \"ChatbotLP\"\nif not os.path.isdir(repo_dir):\n    # Update this URL if you are using a fork / private repo\n    !git clone https://github.com/<YOUR_ORG>/ChatbotLP.git {repo_dir}\n\nos.chdir(repo_dir)\n!pip install -q -r requirements.txt\n</VSCode.Cell>\n\n<VSCode.Cell language=\"python\">\n# 4) Import core modules from the project\nfrom src.gemini_explanation_provider import GeminiExplanationProvider\nfrom src.chatbot_engine import run_chatbot_session\nfrom src.state_manager import StateManager\n\n# Used to register Gemini as the explanation source for `use_llm=True`\nfrom src.llm_adapter import LLMProviderRegistry, RuleBasedProvider\nfrom src.chatbot_engine import IntentRouter\nfrom src.parser import parse_supply_chain_text\nfrom src.response_generator import generate_response\n\n# Schema helpers for constructing a small example\nfrom src.schema import Node, Product, Supplier, Consumer, Bid\n</VSCode.Cell>\n\n<VSCode.Cell language=\"python\">\n# 5) Build a small supply chain problem state\nmgr = StateManager()\nstate = mgr.get_state()\nstate.problem_title = \"Colab Demo: Simple Supply Chain\"\n\n# Nodes\nstate.add_node(Node(id=\"N1\", name=\"Farm\"))\nstate.add_node(Node(id=\"N2\", name=\"Field\"))\n\n# Product\nstate.add_product(Product(id=\"P1\", name=\"Manure\"))\n\n# Supplier + Consumer\nstate.add_supplier(Supplier(id=\"S1\", node=\"N1\", product=\"P1\", capacity=100))\nstate.add_consumer(Consumer(id=\"C1\", node=\"N2\", product=\"P1\", capacity=80))\n\n# Bid (price per unit)\nstate.add_bid(Bid(id=\"B1\", owner_id=\"S1\", owner_type=\"supplier\", product_id=\"P1\", price=0.0, quantity=100))\n\nprint(\"Ready to run. Problem state contains:\")\nprint(\"  nodes:\", [n.id for n in state.nodes])\nprint(\"  products:\", [p.id for p in state.products])\nprint(\"  suppliers:\", [s.id for s in state.suppliers])\nprint(\"  consumers:\", [c.id for c in state.consumers])\n</VSCode.Cell>\n\n<VSCode.Cell language=\"python\">\n# 6) Instantiate GeminiExplanationProvider and register it as the LLM explanation source\ntry:\n    gemini_provider = GeminiExplanationProvider()\n\n    class GeminiLLMProvider(RuleBasedProvider):\n        def get_explanation_generator(self):\n            return gemini_provider\n\n    registry = LLMProviderRegistry.get_instance()\n    registry.set_provider(\n        GeminiLLMProvider(\n            intent_router=IntentRouter(),\n            parse_function=parse_supply_chain_text,\n            generate_function=generate_response,\n        )\n    )\n\n    print(\"GeminiExplanationProvider initialized and registered.\")\nexcept Exception as e:\n    print(\"Could not initialize GeminiExplanationProvider:\", str(e))\n    print(\"The notebook will fall back to rule-based explanations.\")\n</VSCode.Cell>\n\n<VSCode.Cell language=\"python\">\n# 7) Run a chatbot session with use_llm=True (should use Gemini if available)\nresult = run_chatbot_session(state, \"Explain the current problem setup.\", use_llm=True)\n\nprint(\"Intent:\", result.get(\"intent\"))\nprint(\"Success:\", result.get(\"success\"))\nprint(\"\\nGenerated explanation:\\n\", result.get(\"response\"))\n</VSCode.Cell>\n\n<VSCode.Cell language=\"python\">\n# 8) Demonstrate fallback behavior when GEMINI_API_KEY is missing\nimport os\n\n# Clear the key and reset the registry (so LLM provider restarts)\noriginal_key = os.environ.pop(\"GEMINI_API_KEY\", None)\nLLMProviderRegistry.get_instance().reset()\n\nprint(\"GEMINI_API_KEY present after pop?\", \"GEMINI_API_KEY\" in os.environ)\n\nfallback = run_chatbot_session(state, \"Explain the current problem setup.\", use_llm=True)\nprint(\"\\nFallback explanation (rule-based):\\n\", fallback.get(\"response\"))\n\n# Restore the key in case the user wants to rerun later\nif original_key is not None:\n    os.environ[\"GEMINI_API_KEY\"] = original_key\n    print(\"Restored GEMINI_API_KEY in the environment.\")\n</VSCode.Cell>\n\n<VSCode.Cell language=\"markdown\">\n## Notes\n\n- Gemini explanations are generated by calling the Gemini API through `GeminiExplanationProvider`.\n- When the API key is missing or the API call fails, the system falls back to the built-in rule-based explanation generator.\n- This design keeps the mathematical results deterministic while allowing rich natural language explanations.\n</VSCode.Cell>\n"""

# Determine the output path relative to this script
root = Path(__file__).resolve().parents[1]
notebook_path = root / "notebooks" / "colab_supply_chain_chatbot_demo.ipynb"

notebook_path.parent.mkdir(parents=True, exist_ok=True)
with open(notebook_path, "w", encoding="utf-8") as f:
    f.write(NOTEBOOK_CONTENT)

print(f"Wrote notebook to: {notebook_path}")
